7240 /// If we have an icmp le or icmp ge instruction with a constant operand, turn
7241 /// it into the appropriate icmp lt or icmp gt instruction. This transform
7242 /// allows them to be folded in visitICmpInst.
7243 static ICmpInst *canonicalizeCmpWithConstant(ICmpInst &I) {
7244   ICmpInst::Predicate Pred = I.getPredicate();
7245   if (ICmpInst::isEquality(Pred) || !ICmpInst::isIntPredicate(Pred) ||
7246       InstCombiner::isCanonicalPredicate(Pred))
7247     return nullptr;
7248 
7249   Value *Op0 = I.getOperand(0);
7250   Value *Op1 = I.getOperand(1);
7251   auto *Op1C = dyn_cast<Constant>(Op1);
7252   if (!Op1C)
7253     return nullptr;
7254 
7255   auto FlippedStrictness = getFlippedStrictnessPredicateAndConstant(Pred, Op1C);
7256   if (!FlippedStrictness)
7257     return nullptr;
7258 
7259   return new ICmpInst(FlippedStrictness->first, Op0, FlippedStrictness->second);
7260 }
