7262 /// If we have a comparison with a non-canonical predicate, if we can update
7263 /// all the users, invert the predicate and adjust all the users.
7264 CmpInst *InstCombinerImpl::canonicalizeICmpPredicate(CmpInst &I) {
7265   // Is the predicate already canonical?
7266   CmpInst::Predicate Pred = I.getPredicate();
7267   if (InstCombiner::isCanonicalPredicate(Pred))
7268     return nullptr;
7269 
7270   // Can all users be adjusted to predicate inversion?
7271   if (!InstCombiner::canFreelyInvertAllUsersOf(&I, /*IgnoredUser=*/nullptr))
7272     return nullptr;
7273 
7274   // Ok, we can canonicalize comparison!
7275   // Let's first invert the comparison's predicate.
7276   I.setPredicate(CmpInst::getInversePredicate(Pred));
7277   I.setName(I.getName() + ".not");
7278 
7279   // And, adapt users.
7280   freelyInvertAllUsersOf(&I);
7281 
7282   return &I;
7283 }
