1934     // ((X - 1) & ~X) >= 0 --> X != 0
1935     Value *X;
1936     if (match(And->getOperand(0), m_Add(m_Value(X), m_AllOnes())) &&
1937         match(And->getOperand(1), m_Not(m_Specific(X)))) {
1938       auto NewPred = TrueIfNeg ? CmpInst::ICMP_EQ : CmpInst::ICMP_NE;
1939       return new ICmpInst(NewPred, X, ConstantInt::getNullValue(X->getType()));
1940     }
1941     // (X & -X) <  0 --> X == MinSignedC
1942     // (X & -X) > -1 --> X != MinSignedC
1943     if (match(And, m_c_And(m_Neg(m_Value(X)), m_Deferred(X)))) {
1944       Constant *MinSignedC = ConstantInt::get(
