1950   }
1951 
1952   // TODO: These all require that Y is constant too, so refactor with the above.
1953 
1954   // Try to optimize things like "A[i] & 42 == 0" to index computations.
1955   Value *X = And->getOperand(0);
1956   Value *Y = And->getOperand(1);
